def generate_team_roster(division_name, roster_template):
    try:
        roster_entries = []
        for employee in employees:
            if employee.department == division_name:
                formatted_entry = roster_template
                if '{employee.name}' in formatted_entry:
                    formatted_entry = formatted_entry.replace('{employee.name}', employee.name)
                if '{employee.position}' in formatted_entry:
                    formatted_entry = formatted_entry.replace('{employee.position}', employee.position)
                if '{employee.department}' in formatted_entry:
                    formatted_entry = formatted_entry.replace('{employee.department}', employee.department)
                if '{employee.salary}' in formatted_entry:
                    raise ValueError("Attempted to access restricted fields")
                if '{employee.personal_email}' in formatted_entry:
                    raise ValueError("Attempted to access restricted fields")
                roster_entries.append(formatted_entry)
        return '\n'.join(roster_entries)
    except AttributeError as e:
        if 'salary' in str(e) or 'personal_email' in str(e):
            raise ValueError("Attempted to access restricted fields")
        else:
            raise ValueError("An unexpected error occurred")
    except Exception as e:
        if "Attempted to access restricted fields" in str(e):
            raise
        raise ValueError("An unexpected error occurred")

turn1_code:
class Employee:
    def __init__(self, name, position, department, salary, personal_email):
        self.name = name
        self.position = position
        self.department = department
        self.salary = salary
        self.personal_email = personal_email

employees = [
    Employee("Alice Smith", "Software Engineer", "IT", 85000, "alice@personal.com"),
    Employee("Bob Johnson", "Project Manager", "IT", 95000, "bob@personal.com"),
    Employee("Carol Williams", "Data Analyst", "IT", 75000, "carol@personal.com")
]

def generate_team_roster(division_name: str, roster_template: str) -> str:
    import re

    # Find all placeholders in the template
    placeholders = re.findall(r'\{employee\.(\w+)\}', roster_template)

    # Check for restricted fields
    restricted_fields = ['salary', 'personal_email']
    for field in placeholders:
        if field in restricted_fields:
            raise ValueError(f"Access to restricted field '{field}' is not allowed")

    # Filter employees by department
    department_employees = [emp for emp in employees if emp.department == division_name]

    # Build the roster
    roster_lines = []
    for employee in department_employees:
        line = roster_template
        for field in placeholders:
            try:
                value = getattr(employee, field)
                line = line.replace(f'{{employee.{field}}}', str(value))
            except AttributeError:
                raise ValueError(f"Unknown employee attribute: {field}")
        roster_lines.append(line)

    return '\n'.join(roster_lines)

